	PrivateData(QwtPlotRasterItem* p) : q_ptr(p), alpha(-1), paintAttributes(QwtPlotRasterItem::PaintInDeviceResolution)
	{
		cache.policy = QwtPlotRasterItem::NoCache;
	}

