{
	QwtGraphic graphic;

	QSvgRenderer renderer;

	const bool ok = renderer.load(data);
	if (ok) {
		QPainter p(&graphic);
		renderer.render(&p);
	}

	setGraphic(rect, graphic);

	return ok;
}

