/**
 * @brief Return size hint
 * @sa minimumSizeHint()
 */
QSize QwtDial::sizeHint() const
{
	int sh = 0;
	if (scaleDraw())
		sh = qwtCeil(scaleDraw()->extent(font()));

	const int d = 6 * sh + 2 * lineWidth();

	QSize hint(d, d);
	if (!isReadOnly())
		hint = qwtExpandedToGlobalStrut(hint);

	return hint;
}

