	d->m_caption.setFont("Courier", 10, QFont::Bold);
	d->m_caption.setColor(RGBA(0, 0, 0, 1));
	setRelPosition(Tuple(0.94, 1 - 0.36), Tuple(0.97, 1 - 0.04));
